 using Microsoft.Extensions.Logging;
 using ModelContextProtocol.Server;

 namespace WeatherMcpServer;

 [McpServerToolType]
 public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
 {
     private const string BaseUrl = "https://api.open-meteo.com/v1";

     [McpServerTool, Description("Get the current weather for a location given its latitude and longitude.")]
     public async Task<string> GetCurrentWeather(
         [Description("Latitude of the location (e.g. 47.6062 for Seattle)")] double latitude,
         [Description("Longitude of the location (e.g. -122.3321 for Seattle)")] double longitude,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

         var url = $"{BaseUrl}/forecast?latitude={latitude}&longitude={longitude}"
                 + "&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

         var response = await httpClient.GetStringAsync(url, cancellationToken);

         using var doc = JsonDocument.Parse(response);
         var current = doc.RootElement.GetProperty("current");

         return $"Temperature: {current.GetProperty("temperature_2m")}°C, "
              + $"Wind: {current.GetProperty("wind_speed_10m")} km/h, "
              + $"Humidity: {current.GetProperty("relative_humidity_2m")}%";
     }

     [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
     public async Task<string> GetForecast(
         [Description("Latitude of the location")] double latitude,
         [Description("Longitude of the location")] double longitude,
         [Description("Number of forecast days (1-7)")] int days = 3,
         CancellationToken cancellationToken = default)
     {
         days = Math.Clamp(days, 1, 7);
         logger.LogInformation("Fetching {Days}-day forecast for ({Lat}, {Lon})", days, latitude, longitude);

         var url = $"{BaseUrl}/forecast?latitude={latitude}&longitude={longitude}"
                 + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

         var response = await httpClient.GetStringAsync(url, cancellationToken);

         using var doc = JsonDocument.Parse(response);
         var daily = doc.RootElement.GetProperty("daily");
         var dates = daily.GetProperty("time").EnumerateArray().ToArray();
         var maxTemps = daily.GetProperty("temperature_2m_max").EnumerateArray().ToArray();
         var minTemps = daily.GetProperty("temperature_2m_min").EnumerateArray().ToArray();

         var lines = dates.Select((d, i) =>
             $"{d}: High {maxTemps[i]}°C, Low {minTemps[i]}°C");

         return string.Join("\n", lines);
     }
 }

